import elasticsearch

es = elasticsearch.Elasticsearch(['localhost:9200'])

# Index a document
doc = {'title': 'My Document', 'content': 'This is my document content'}
es.index(index='my-index', body=doc)

# Search for documents
query = {'query': {'match': {'title': 'My Document'}}}
results = es.search(index='my-index', body=query)
print(results['hits']['hits'])

# Aggregate logs
logs = [{'timestamp': '2023-01-01T12:00:00Z', 'message': 'This is a log message'}, {'timestamp': '2023-01-01T13:00:00Z', 'message': 'This is another log message'}]
es.bulk(index='my-log-index', body=logs)